#include <bits/stdc++.h>
using namespace std;

using ll = long long;

// Convert binary to Gray code
ll to_gray(ll n) {
    return n ^ (n >> 1);
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    while (n--) {
        ll x, y;
        cin >> x >> y;

        // Transform coordinates
        ll u = x + y;
        ll v = x - y;

        // Determine curve index based on parity
        int curve;
        if ((u & 1) && (v & 1)) {
            // Both odd
            curve = 3;
        } else if ((u & 1) && !(v & 1)) {
            // u odd, v even
            curve = 4;
        } else if (!(u & 1) && (v & 1)) {
            // u even, v odd
            curve = 2;
        } else {
            // Both even
            curve = 1;
        }

        // Compute segment position using Gray codes
        // Shift right by 1 to handle the division by 2
        ll a = (u - (u & 1)) / 2;
        ll b = (v - (v & 1)) / 2;

        // Take absolute values for Gray code conversion
        ll ga = to_gray(a >= 0 ? a : -a - 1);
        ll gb = to_gray(b >= 0 ? b : -b - 1);

        // Combine Gray codes to get position
        ll pos = 1 + ((ga << 1) | (gb & 1));
        for (ll bit = 1; bit <= 60; bit++) {
            if (gb & (1LL << bit)) {
                pos |= (1LL << (bit + 1));
            }
        }

        cout << curve << ' ' << pos << '\n';
    }
    return 0;
}

